async (params, browser) => {
  // Open Glassdoor salary page
  await browser.open(`${params.salaries_url}`)

  // Wait for salary data to load
  await browser.waitForSelector('[data-test="salary-row"], .salaryRow, [class*="SalaryRowStyle__row"], .salary-list-row, table tbody tr, [class*="SalariesList"] > div', 15000)

  // Let salary data render
  await browser.wait(2500)

  // Scroll to load more salaries
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Extract salary information
  const salary_data = await browser.evaluate(`const salaries = []; const rows = document.querySelectorAll('[data-test="salary-row"], .salaryRow, [class*="SalaryRowStyle__row"], .salary-list-row, table tbody tr, [class*="SalariesList"] > div'); for (let i = 0; i < Math.min(rows.length, 15); i++) { const row = rows[i]; const titleEl = row.querySelector('[data-test="salary-job-title"], [class*="salaryRow__JobInfoStyle__jobTitle"], a[href*="/Salaries/"], h3, .job-title, strong'); const avgSalaryEl = row.querySelector('[data-test="salary-average"], .salary-avg, [class*="SalaryRowStyle__payAmount"], .salary-amount, .mean'); const rangeEl = row.querySelector('[data-test="salary-range"], .salary-range, [class*="SalaryRowStyle__payRange"], .range'); const countEl = row.querySelector('[data-test="salary-count"], .salary-count, [class*="SalaryRowStyle__payCount"], .num-salaries'); const linkEl = row.querySelector('a[href*="/Salary/"], a[href*="/Salaries/"]'); let url = ''; if (linkEl) { const href = linkEl.getAttribute('href') || ''; url = href.startsWith('http') ? href : 'https://www.glassdoor.com' + href; } salaries.push({ job_title: titleEl ? titleEl.textContent.trim() : '', average_salary: avgSalaryEl ? avgSalaryEl.textContent.trim() : '', salary_range: rangeEl ? rangeEl.textContent.trim() : '', report_count: countEl ? countEl.textContent.trim() : '', url: url }); } const companyEl = document.querySelector('[data-test="employer-name"], .employer-name, h1'); return { company: companyEl ? companyEl.textContent.trim() : '', salary_count: salaries.length, salaries: salaries, salaries_url: window.location.href }`)

  return salary_data
}
